+        assertEquals(0.01, parseDouble("1e-2"), 0.0);
+        assertEquals(100.0, parseDouble("1e0002"), 0.0);
+        assertEquals(1.0, parseDouble("1e-0"), 0.0);
+    }
+
+    @Test
+    public void parseSubstringRanges() {
