+        assertNumberFormatException("");
+        assertNumberFormatException("+");
+        assertNumberFormatException("-");
+        assertNumberFormatException(".");
+        assertNumberFormatException("+.");
+        assertNumberFormatException("-.");
+        assertNumberFormatException("e1");
+        assertNumberFormatException("+e1");
+    }
+
+    @Test
