+    private static String randomNumber(Random rnd, int maxIntDigits, int maxFracDigits, int maxAbsExp) {
+        StringBuilder sb = new StringBuilder(32);
+
+        int sign = rnd.nextInt(5);
+        if (sign == 0) {
+            sb.append('-');
+        } else if (sign == 1) {
+            sb.append('+');
+        }
